import numpy as np

def select_next_node(current_node, truck_nodes, depot_node, unvisited_nodes, distance_matrix):
    if len(unvisited_nodes) == 0:
        return depot_node

    min_distance = float('inf')
    next_node = None

    for node in unvisited_nodes:
        if node in truck_nodes:
            continue

        distance_to_node = distance_matrix[current_node, node]
        distance_from_node_to_depot = distance_matrix[node, depot_node]

        weighted_distance = distance_to_node + distance_from_node_to_depot

        if weighted_distance < min_distance:
            min_distance = weighted_distance
            next_node = node

    return next_node
